function daysBetween(y1,m1,d1,y2,m2,d2) {
    return Math.round((new Date(y2,m2-1,d2) - new Date(y1,m1-1,d1)) / 86400000);
}

function getLunarDate(gy,gm,gd) {
    const entry = lunarData[gy];
    let lunarYear = gy;
    if (entry) {
        if (daysBetween(gy,entry[0],entry[1],gy,gm,gd) < 0) lunarYear = gy - 1;
    } else {
        lunarYear = gy - 1;
    }
    const lye = lunarData[lunarYear];
    if (!lye) return null;
    const [cnyM,cnyD,monthLens,leapAfter,leapLen] = lye;
    const dfc = daysBetween(lunarYear,cnyM,cnyD,gy,gm,gd);
    const months = [];
    for (let i=0; i<12; i++) {
        months.push({m:i+1, leap:false, days:monthLens[i]});
        if (leapAfter===i+1 && leapLen>0) months.push({m:i+1, leap:true, days:leapLen});
    }
    let cum=0, lunarM=1, lunarD=1, isLeap=false;
    for (const mo of months) {
        if (dfc < cum+mo.days) { lunarM=mo.m; isLeap=mo.leap; lunarD=dfc-cum+1; break; }
        cum += mo.days;
    }
    const si=(lunarYear-4)%10, bi=(lunarYear-4)%12;
    return {
        zodiacSign: zodiacOrder[bi],
        yearCn:  stemsCn[si]+branchCn[bi]+"年",
        yearEn:  stemsEn[si]+" ("+elemEn[si]+") · "+branchEn[bi]+" Year",
        monthCn: (isLeap?"閏":"")+monthCnNames[lunarM-1],
        monthEn: (isLeap?"Leap ":"")+monthEnNames[lunarM-1],
        dayCn:   dayCnArr[lunarD]||(lunarD+"日"),
        dayEn:   (dayEnArr[lunarD]||lunarD+"th")+" Day"
    };
}

function revealZodiac() {
    const val = document.getElementById('birthday').value;
    if (!val) return;
    const [gy,gm,gd] = val.split('-').map(Number);
    const lunar = getLunarDate(gy,gm,gd);
    if (!lunar) return;
    const sign = lunar.zodiacSign;
    const data = profiles[sign];
    document.getElementById('resBigName').innerText  = sign.toUpperCase();
    document.getElementById('resZodiacImg').src       = zodiacImages[sign]||'';
    document.getElementById('resZodiacImg').alt       = sign+' zodiac illustration';
    document.getElementById('resElement').innerText   = data.element;
    document.getElementById('resSpirit').innerText    = data.spirit;
    document.getElementById('resProfile').innerText   = data.text;
    document.getElementById('lunarYear').innerText    = lunar.yearCn;
    document.getElementById('lunarYearEn').innerText  = lunar.yearEn;
    document.getElementById('lunarMonth').innerText   = lunar.monthCn;
    document.getElementById('lunarMonthEn').innerText = lunar.monthEn;
    document.getElementById('lunarDay').innerText     = lunar.dayCn;
    document.getElementById('lunarDayEn').innerText   = lunar.dayEn;
    document.getElementById('result').style.display = 'block';
    window.scrollTo({top:document.getElementById('result').offsetTop-20, behavior:'smooth'});
}

